package com.gabriel.benchmark;

/**
 * Utility class for measuring algorithm execution time.
 */
public final class Benchmark {

    private Benchmark() {
        throw new AssertionError("Utility class");
    }

    /**
     * Measures the execution time of an algorithm.
     *
     * @param algorithmName name of the algorithm
     * @param algorithm algorithm to benchmark
     * @return benchmark result containing the execution time
     */
    public static BenchmarkResult run(String algorithmName, Runnable algorithm) {

        long start = System.nanoTime();

        algorithm.run();

        long end = System.nanoTime();

        return new BenchmarkResult(
                algorithmName,
                end - start
        );
    }
}
